    \draw (0,0) -- (90:2);
    \draw (0,0) -- (90-135:2);
    % Cruise: 30°
    \draw (0,0) -- (90-135-30:2);
    % Lake: 75°
    \draw (0,0) -- (90-135-30-75:2);
    % Mountain: 120° (completes the circle)

    % Labels
    \node at (90-67.5:1.3) {Beach};
    \node at (90-135-15:1.3) {Cruise};
    \node at (90-135-30-37.5:1.3) {Lake};
    \node at (90-135-30-75-60:1.3) {Mountain};

    % Angles
    \node at (90-67.5:0.6) {$135\degree$};
    \node at (90-135-15:0.6) {$30\degree$};
    \node at (90-135-30-37.5:0.6) {$75\degree$};
    \node at (90-135-30-75-60:0.6) {$120\degree$};
\end{tikzpicture}
\end{center}

\begin{subparts}

\subpart Find the fraction of people who prefer a mountain holiday.

Give your answer in its simplest form.
\AnswerLine[][]
\Marks{2}

\subpart Find the percentage of people who prefer a beach holiday.
\AnswerLine[][\%]
\Marks{1}

\subpart Find the ratio of people who prefer each type of holiday in the form

\begin{center}
beach : cruise : lake : mountain.
\end{center}

Give your answer in its simplest form.
\AnswerLine[.................... : .................... : .................... : ....................][][4]
\Marks{2}

\subpart One person is chosen at random.

Find the probability that this person prefers a cruise or a lake holiday.
\AnswerLine[][]
\Marks{2}

\subpart 675 people prefer a beach holiday.

Show that the total number of people Chen asks is 1800.
\AnswerLine[show][]
\Marks{1}

\subpart
\begin{subsubparts}

\subsubpart Complete the table.

\relinput{Figures/Q02avia.tex}

